<script setup lang="ts">
import { onMounted, ref } from 'vue'; import { userApi } from '@/api/services'; import PageState from '@/shared/PageState.vue'; import { bytes, date } from '@/shared/format'
const loading=ref(true), error=ref(''), data=ref<any>({}); async function load(){loading.value=true;try{data.value=await userApi.subscribe()}catch(e:any){error.value=e.message}finally{loading.value=false}} onMounted(load)
function copy(){navigator.clipboard.writeText(data.value.subscribe_url || data.value.url || '');}
</script>
<template><PageState :loading="loading" :error="error" @retry="load"><div class="page-heading"><div><h1>我的订阅</h1><p>查看用量，并将订阅导入常用客户端。</p></div></div><section class="detail-grid"><div class="panel detail-card"><h2>订阅信息</h2><dl><div><dt>上传流量</dt><dd>{{ bytes(data.u) }}</dd></div><div><dt>下载流量</dt><dd>{{ bytes(data.d) }}</dd></div><div><dt>总流量</dt><dd>{{ bytes(data.transfer_enable) }}</dd></div><div><dt>到期时间</dt><dd>{{ date(data.expired_at) }}</dd></div></dl></div><div class="panel detail-card"><h2>订阅地址</h2><p class="muted">请妥善保管订阅地址，泄漏后请及时重置。</p><div class="copy-row"><input readonly :value="data.subscribe_url || data.url || '暂无订阅地址'"/><button class="button primary" @click="copy">复制</button></div><div class="client-actions"><button class="button secondary">Clash Verge</button><button class="button secondary">Shadowrocket</button><button class="button secondary">v2rayN</button></div></div></section></PageState></template>
